import React from "react";

const GetInTouch = ({ heading, message1, email, message2, phoneNumber }) => {
  return (
    <>
      <h2 className="display-4 pb-3 text-center">{heading}</h2>
      <p className="lead text-center pb-3">
        {message1 && <>{message1} </>}

        {email && (
          <a className="text-decoration-none" href={`mailto:${email}`}>
            {email}
          </a>
        )}

        {message2 && <> {message2} </>}

        {phoneNumber && (
          <>
            {" "}
            <a className="text-decoration-none" href={`tel:${phoneNumber}`}>
              {phoneNumber}
            </a>
          </>
        )}
      </p>
    </>
  );
};

export default GetInTouch;
